    // FFI annotation symbols
    SymbolId sym_ffi;       // "ffi" for [ffi ...] annotation
    SymbolId sym_lib;       // "lib" for [ffi lib]
    SymbolId sym_Ptr;       // "Ptr" for ^Ptr type
    SymbolId sym_Void;      // "Void" for ^Void type

    // Built-in type name symbols
    SymbolId sym_Int;
    SymbolId sym_Double;
    SymbolId sym_String;
    SymbolId sym_Symbol;
    SymbolId sym_List;
