// ScopeHandle operations
// =============================================================================

/**
 * Create a ScopeHandle from a ScopeRegion pointer.
 */
fn ScopeHandle scope_handle_from(ScopeRegion* region) @inline {
    if (region == null) return SCOPE_HANDLE_NULL;
    ScopeHandle h;
    h.region = region;
    h.generation = region.generation;
    return h;
}

