// Scope splitting (for closure capture optimization)
// =============================================================================

/**
 * Decide how to capture a scope for a closure.
 * If the original scope is small, just retain it.
 * If large and few captures, create a mini capture-scope with copies.
 *
 * Returns a scope that the closure should hold (already retained or newly created).
 * The caller does NOT need to call scope_retain on the result.
 */
fn ScopeRegion* capture_scope_for_closure(ScopeRegion* original) {
    // For now, always retain the whole scope.
    // Splitting will be implemented in Phase 4 when we have capture tracking.
    scope_retain(original);
    return original;
}

// =============================================================================
// Freelist cleanup (for shutdown)
// =============================================================================

/**
 * Free all ScopeRegion structs in the global freelist.
 * Call at program shutdown.
 */
fn void scope_freelist_cleanup() {
    ScopeRegion* s = g_scope_freelist;
    while (s != null) {
        ScopeRegion* next = s.pool_next;
        mem::free(s);
        s = next;
    }
    g_scope_freelist = null;
    g_scope_freelist_count = 0;
}

