// =============================================================================
// ScopeHandle operations
// =============================================================================

/**
 * Create a ScopeHandle from a ScopeRegion pointer.
 */
fn ScopeHandle scope_handle_from(ScopeRegion* region) @inline {
    if (region == null) return SCOPE_HANDLE_NULL;
    ScopeHandle h;
    h.region = region;
    h.generation = region.generation;
    return h;
}

/**
 * Check if a ScopeHandle is still valid (region not recycled).
 */
fn bool scope_handle_valid(ScopeHandle h) @inline {
    return h.region != null && h.region.generation == h.generation;
}

/**
 * Dereference a ScopeHandle to get the ScopeRegion pointer.
 * Returns null if the handle is invalid (region was recycled).
 */
fn ScopeRegion* scope_handle_deref(ScopeHandle h) @inline {
    if (h.region != null && h.region.generation == h.generation) {
        return h.region;
    }
    return null;
}

