367→// =============================================================================
368→
369→fn void run_scope_region_tests() {
370→    io::print("  Scope region tests... ");
371→    usz passed = 0;
372→    usz failed = 0;
373→
374→    // Test 1: Create and destroy a scope
375→    {
376→        ScopeRegion* s = scope_create(null);
377→        if (s != null && s.refcount == 1 && s.parent == null && s.chunks != null) {
378→            passed++;
379→        } else {
380→            io::printn("FAIL: scope_create basic");
381→            failed++;
382→        }
383→        scope_release(s);
384→        passed++; // didn't crash
385→    }
386→
387→    // Test 2: Bump allocation
388→    {
389→        ScopeRegion* s = scope_create(null);
390→        void* p1 = s.alloc(24);  // Value-sized
391→        void* p2 = s.alloc(24);
392→        void* p3 = s.alloc(8);
393→        // Allocations should be sequential (8-byte aligned)
394→        if (p1 != null && p2 != null && p3 != null) {
395→            usz diff = (usz)p2 - (usz)p1;
396→            if (diff == 24) { passed++; } else { io::printfn("FAIL: bump sequential (diff=%d)", (int)diff); failed++; }
397→        } else {
398→            io::printn("FAIL: bump alloc returned null");
399→            failed++;
400→        }
401→        if (s.alloc_count == 3) { passed++; } else { io::printn("FAIL: alloc_count"); failed++; }
402→        if (s.alloc_bytes == 24 + 24 + 8) { passed++; } else { io::printfn("FAIL: alloc_bytes=%d", (int)s.alloc_bytes); failed++; }
403→        scope_release(s);
404→    }
405→
406→    // Test 3: Chunk overflow (allocate more than initial chunk)
407→    {
408→        ScopeRegion* s = scope_create(null);
409→        // Fill initial chunk (512 bytes) and overflow
410→        for (usz i = 0; i < 100; i++) {
411→            void* p = s.alloc(64);  // 100 * 64 = 6400 bytes
412→            if (p == null) { io::printn("FAIL: overflow alloc null"); failed++; break; }
413→        }
414→        // Should have multiple chunks
415→        usz chunk_count = 0;
416→        ScopeChunk* c = s.chunks;
417→        while (c != null) { chunk_count++; c = c.next; }
418→        if (chunk_count > 1) { passed++; } else { io::printn("FAIL: no overflow chunks"); failed++; }
419→        scope_release(s);
420→        passed++;
421→    }
422→
423→    // Test 4: Reference counting (parent-child)
424→    {
425→        ScopeRegion* parent = scope_create(null);
426→        ScopeRegion* child = scope_create(parent);
427→        // Parent RC should be 2 (original + child's reference)
428→        if (parent.refcount == 2) { passed++; } else { io::printfn("FAIL: parent RC=%d", (int)parent.refcount); failed++; }
429→        if (child.refcount == 1) { passed++; } else { io::printfn("FAIL: child RC=%d", (int)child.refcount); failed++; }
430→        if (child.parent == parent) { passed++; } else { io::printn("FAIL: child.parent"); failed++; }
431→        // Release child — parent RC drops to 1
432→        scope_release(child);
433→        if (parent.refcount == 1) { passed++; } else { io::printfn("FAIL: parent RC after child release=%d", (int)parent.refcount); failed++; }
434→        scope_release(parent);
435→        passed++;
436→    }
437→
438→    // Test 5: Destructor execution
439→    {
440→        ScopeRegion* s = scope_create(null);
441→        // Allocate a small heap buffer, register its destructor
442→        int* counter = (int*)mem::malloc(int.sizeof);
443→        *counter = 0;
444→
445→        // We'll use a trick: allocate an int in the scope, point dtor at the malloc'd counter
446→        // The destructor increments the counter
447→        scope_register_dtor(s, (void*)counter, fn void(void* ptr) {
448→            int* c = (int*)ptr;
449→            *c = *c + 1;
450→        });
451→        scope_register_dtor(s, (void*)counter, fn void(void* ptr) {
452→            int* c = (int*)ptr;
453→            *c = *c + 10;
454→        });
455→
456→        // Destroy scope — dtors should run in LIFO order (10 first, then 1)
457→        scope_release(s);
458→        if (*counter == 11) { passed++; } else { io::printfn("FAIL: dtor counter=%d", *counter); failed++; }
459→        mem::free(counter);
460→    }
461→
462→    // Test 6: Freelist recycling (generation increment)
463→    {
464→        ScopeRegion* s = scope_create(null);
465→        uint gen_before = s.generation;
466→        scope_release(s);
467→        // After release, scope should be in freelist with incremented generation
468→        // Create a new scope — should get the recycled one
469→        ScopeRegion* s2 = scope_create(null);
470→        if (s2.generation == gen_before + 1) { passed++; } else { io::printfn("FAIL: gen=%d expected=%d", (int)s2.generation, (int)(gen_before + 1)); failed++; }
471→        scope_release(s2);
472→    }
473→
474→    // Test 7: Scope reset (loop reuse)
475→    {
476→        ScopeRegion* s = scope_create(null);
477→        // Allocate some data
478→        void* p1 = s.alloc(64);
479→        void* p2 = s.alloc(64);
480→
481→        int* dtor_counter = (int*)mem::malloc(int.sizeof);
482→        *dtor_counter = 0;
483→        scope_register_dtor(s, (void*)dtor_counter, fn void(void* ptr) {
484→            int* c = (int*)ptr;
485→            *c = *c + 1;
486→        });
487→
488→        // Reset the scope
489→        scope_reset(s);
490→        if (*dtor_counter == 1) { passed++; } else { io::printfn("FAIL: reset dtor counter=%d", *dtor_counter); failed++; }
491→        if (s.alloc_bytes == 0) { passed++; } else { io::printn("FAIL: reset alloc_bytes"); failed++; }
492→        if (s.alloc_count == 0) { passed++; } else { io::printn("FAIL: reset alloc_count"); failed++; }
493→        if (s.dtors == null) { passed++; } else { io::printn("FAIL: reset dtors"); failed++; }
494→
495→        // Can allocate again after reset
496→        void* p3 = s.alloc(32);
497→        if (p3 != null) { passed++; } else { io::printn("FAIL: alloc after reset"); failed++; }
498→
499→        scope_release(s);
500→        mem::free(dtor_counter);
501→    }
502→
503→    // Test 10: Large allocation (bigger than initial chunk)
504→    {
505→        ScopeRegion* s = scope_create(null);
506→        void* big = s.alloc(2048);  // Bigger than initial 512-byte chunk
507→        if (big != null) { passed++; } else { io::printn("FAIL: large alloc"); failed++; }
508→        scope_release(s);
509→    }
510→
511→    // Test 11: Deep parent chain
512→    {
513→        ScopeRegion* root = scope_create(null);
514→        ScopeRegion* prev = root;
515→        for (usz i = 0; i < 10; i++) {
516→            ScopeRegion* child = scope_create(prev);
517→            if (i > 0) scope_release(prev);  // Release our reference (child holds one)
518→            prev = child;
519→        }
520→        // Release the leaf — should cascade all the way up
521→        if (root.refcount == 2) { passed++; } else { io::printfn("FAIL: deep chain root RC=%d", (int)root.refcount); failed++; }
522→        scope_release(prev);
523→        // Root should now have RC=1 (our original reference)
524→        if (root.refcount == 1) { passed++; } else { io::printfn("FAIL: deep chain root RC after cascade=%d", (int)root.refcount); failed++; }
525→        scope_release(root);
526→        passed++;
527→    }
528→
529→    // Test 12: Retain/release symmetry
530→    {
531→        ScopeRegion* s = scope_create(null);
532→        scope_retain(s);
533→        scope_retain(s);
534→        if (s.refcount == 3) { passed++; } else { io::printfn("FAIL: triple retain RC=%d", (int)s.refcount); failed++; }
535→        scope_release(s);
536→        scope_release(s);
537→        if (s.refcount == 1) { passed++; } else { io::printfn("FAIL: after double release RC=%d", (int)s.refcount); failed++; }
538→        scope_release(s);
539→        passed++;
540→    }
541→
542→    // Test 13: Alignment check
543→    {
544→        ScopeRegion* s = scope_create(null);
545→        void* p1 = s.alloc(1);   // 1 byte → 8-aligned
546→        void* p2 = s.alloc(3);   // 3 bytes → 8-aligned
547→        void* p3 = s.alloc(16);  // 16 bytes → 16-aligned (already 8-aligned)
548→        if ((usz)p1 % 8 == 0) { passed++; } else { io::printn("FAIL: align p1"); failed++; }
549→        if ((usz)p2 % 8 == 0) { passed++; } else { io::printn("FAIL: align p2"); failed++; }
550→        if ((usz)p3 % 8 == 0) { passed++; } else { io::printn("FAIL: align p3"); failed++; }
551→        // p2 should be 8 bytes after p1 (1 byte rounded up to 8)
552→        usz gap = (usz)p2 - (usz)p1;
553→        if (gap == 8) { passed++; } else { io::printfn("FAIL: align gap=%d", (int)gap); failed++; }
554→        scope_release(s);
555→    }
556→
557→    io::printfn("%d passed, %d failed", (int)passed, (int)failed);
558→}
