  8→/**
  9→ * AOT build: compile Lisp source to standalone binary.
 10→ * Usage: ./main --build input.lisp -o output_binary
 11→ */
 12→fn int run_build(int argc, char** argv, int build_idx) {
 13→    char* input_file = null;
 14→    char* output_binary = null;
 15→
 16→    // Parse: --build input.lisp [-o output]
 17→    if (build_idx + 1 < argc) {
 18→        input_file = argv[build_idx + 1];
 19→    }
 20→    for (int i = build_idx + 2; i < argc; i++) {
 21→        if (str_eq(argv[i], "-o") && i + 1 < argc) {
 22→            output_binary = argv[i + 1];
 23→            break;
 24→        }
 25→    }
 26→
 27→    if (input_file == null) {
 28→        io::printn("Usage: ./main --build input.lisp [-o output]");
 29→        return 1;
 30→    }
 31→
 32→    // Default output name: strip extension, or append .out
 33→    char[512] default_out;
 34→    usz default_out_len = 0;
 35→    if (output_binary == null) {
 36→        char* p = input_file;
 37→        usz input_len = 0;
 38→        while (*p != 0) { input_len++; p++; }
 39→        // Find last dot
 40→        isz last_dot = -1;
 41→        for (usz i = 0; i < input_len; i++) {
 42→            if (input_file[i] == '.') last_dot = (isz)i;
 43→        }
 44→        if (last_dot > 0) {
 45→            default_out_len = (usz)last_dot;
 46→        } else {
 47→            default_out_len = input_len;
 48→        }
 49→        for (usz i = 0; i < default_out_len && i < 511; i++) {
 50→            default_out[i] = input_file[i];
 51→        }
 52→        default_out[default_out_len] = 0;
 53→        output_binary = &default_out[0];
 54→    }
 55→
 56→    // Read input file
 57→    usz input_path_len = 0;
 58→    char* ip = input_file;
 59→    while (*ip != 0) { input_path_len++; ip++; }
 60→    char[] input_path = input_file[:input_path_len];
 61→
 62→    char[] source;
 63→    if (try s = io::file::load_temp((String)input_path)) {
 64→        source = s;
 65→    } else {
 66→        io::printfn("Error: cannot read input file '%s'", (ZString)input_file);
 67→        return 1;
 68→    }
 69→
 70→    // Step 1: Compile Lisp → C3
 71→    io::printfn("Compiling %s...", (ZString)input_file);
 72→    thread_registry_init();
 73→    lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
 74→    interp.init();
 75→
 76→    char[] c3_code = lisp::compile_to_c3(source, interp);
 77→
 78→    // Step 2: Write temp C3 file
 79→    char[] temp_path = "build/_aot_temp.c3";
 80→    if (try file = io::file::open((String)temp_path, "w")) {
 81→        defer (void)file.close();
 82→        file.write(c3_code)!!;
 83→    } else {
 84→        io::printn("Error: cannot write temp file build/_aot_temp.c3");
 85→        mem::free(interp);
 86→        thread_registry_shutdown();
 87→        return 1;
 88→    }
 89→
 90→    // Step 3: Invoke c3c to compile
 91→    io::printfn("Building %s...", (ZString)output_binary);
 92→
 93→    // Build the c3c command
 94→    usz out_len = 0;
 95→    char* op = output_binary;
 96→    while (*op != 0) { out_len++; op++; }
 97→
 98→    char[1024] cmd_buf;
 99→    usz cmd_len = 0;
100→    // Standalone AOT: only 5 source files, no interpreter/JIT/replxx/lightning
101→    char[] prefix = "env -u LD_LIBRARY_PATH c3c compile src/main.c3 src/continuation.c3 src/ghost_index.c3 src/lisp/runtime.c3 build/_aot_temp.c3 -l dl -l m -L /usr/local/lib -o ";
102→    for (usz i = 0; i < prefix.len && cmd_len < 1023; i++) {
103→        cmd_buf[cmd_len] = prefix[i];
104→        cmd_len++;
105→    }
106→    for (usz i = 0; i < out_len && cmd_len < 1023; i++) {
107→        cmd_buf[cmd_len] = output_binary[i];
108→        cmd_len++;
109→    }
110→    cmd_buf[cmd_len] = 0;
111→
112→    int exit_code = system(&cmd_buf[0]);
113→
114→    mem::free(interp);
115→    thread_registry_shutdown();
116→
117→    if (exit_code != 0) {
118→        io::printn("Error: c3c compilation failed");
119→        return 1;
120→    }
121→
122→    io::printfn("Built: %s", (ZString)output_binary);
123→    return 0;
124→}
