129→ * Scaffold a new Omni project directory.
130→ * Usage: ./main --init myproject
131→ */
132→fn int run_init(int argc, char** argv, int init_idx) {
133→    if (init_idx + 1 >= argc) {
134→        io::printn("Usage: ./main --init <project-name>");
135→        return 1;
136→    }
137→    char* name = argv[init_idx + 1];
138→    usz name_len = 0;
139→    char* np = name;
