270→/**
271→ * Generate FFI bindings from omni.toml using libclang.
272→ * Usage: ./main --bind [project-dir]
273→ */
274→fn int run_bind(int argc, char** argv, int bind_idx) {
275→    // Determine project directory (next arg or ".")
276→    char[512] proj_dir;
277→    usz proj_dir_len;
278→    if (bind_idx + 1 < argc) {
279→        char* dir = argv[bind_idx + 1];
280→        proj_dir_len = 0;
281→        while (dir[proj_dir_len] != 0 && proj_dir_len < 510) {
282→            proj_dir[proj_dir_len] = dir[proj_dir_len];
283→            proj_dir_len++;
284→        }
285→        // Strip trailing slash
286→        if (proj_dir_len > 0 && proj_dir[proj_dir_len - 1] == '/') proj_dir_len--;
287→        proj_dir[proj_dir_len] = 0;
288→    } else {
289→        proj_dir[0] = '.';
290→        proj_dir[1] = 0;
291→        proj_dir_len = 1;
292→    }
293→
294→    // Load omni.toml
295→    char[512] toml_path;
296→    usz tlen = 0;
297→    for (usz i = 0; i < proj_dir_len; i++) { toml_path[tlen] = proj_dir[i]; tlen++; }
298→    toml_path[tlen] = '/'; tlen++;
299→    char[] toml_suffix = "omni.toml";
300→    for (usz i = 0; i < toml_suffix.len; i++) { toml_path[tlen] = toml_suffix[i]; tlen++; }
301→    toml_path[tlen] = 0;
302→
303→    lisp::TomlConfig* config = (lisp::TomlConfig*)mem::malloc(lisp::TomlConfig.sizeof);
304→    defer mem::free(config);
305→
306→    if (!lisp::toml_load(toml_path[:tlen], config)) {
307→        io::printfn("Error: cannot read %s", (ZString)&toml_path[0]);
308→        return 1;
309→    }
310→
311→    if (config.ffi_dep_count == 0) {
312→        io::printn("No FFI dependencies found in omni.toml");
313→        io::printn("Add a [dependencies.ffi.NAME] section to generate bindings.");
314→        return 0;
315→    }
316→
317→    // Initialize libclang
318→    lisp::LibclangHandle clang;
319→    if (!lisp::libclang_init(&clang)) {
320→        io::printn("Error: libclang not found.");
321→        io::printn("");
322→        io::printn("Install libclang:");
323→        io::printn("  Arch:   pacman -S clang");
324→        io::printn("  Debian: apt install libclang-dev");
325→        io::printn("  Fedora: dnf install clang-devel");
326→        return 1;
327→    }
328→    defer lisp::libclang_destroy(&clang);
329→
330→    // Allocate parsed functions buffer
331→    const usz MAX_FUNCS = 256;
332→    lisp::ParsedFunc* funcs = (lisp::ParsedFunc*)mem::malloc(lisp::ParsedFunc.sizeof * MAX_FUNCS);
333→    defer mem::free(funcs);
334→
335→    usz total_bindings = 0;
336→    usz total_libs = 0;
337→
338→    for (usz dep_idx = 0; dep_idx < config.ffi_dep_count; dep_idx++) {
339→        lisp::TomlFfiDep* dep = &config.ffi_deps[dep_idx];
340→
341→        // Get null-terminated name and library
342→        char* dep_name = &dep.name;
343→        char* dep_lib = &dep.library;
344→
345→        io::printfn("Parsing headers for '%s' (lib%s)...", (ZString)dep_name, (ZString)dep_lib);
346→
347→        usz func_count = 0;
348→
349→        // Parse each header
350→        for (usz hi = 0; hi < dep.header_count; hi++) {
351→            char* header = &dep.headers[hi];
352→            usz hlen = 0;
353→            while (header[hlen] != 0) hlen++;
354→
355→            usz found = lisp::parse_header(&clang, header[:hlen],
356→                                           &funcs[func_count], MAX_FUNCS - func_count,
357→                                           &dep.functions, dep.function_count, dep.filter_functions);
358→            func_count += found;
359→        }
360→
361→        if (func_count == 0) {
362→            io::printfn("  Warning: no functions found for '%s'", (ZString)dep_name);
363→            continue;
364→        }
365→
366→        // Build output path: {proj_dir}/lib/ffi/{name}.omni
367→        char[512] out_path;
368→        usz olen = 0;
369→        for (usz i = 0; i < proj_dir_len; i++) { out_path[olen] = proj_dir[i]; olen++; }
370→        char[] ffi_mid = "/lib/ffi/";
371→        for (usz i = 0; i < ffi_mid.len; i++) { out_path[olen] = ffi_mid[i]; olen++; }
372→        usz nlen = 0;
373→        while (dep_name[nlen] != 0) { out_path[olen] = dep_name[nlen]; olen++; nlen++; }
374→        char[] omni_ext = ".omni";
375→        for (usz i = 0; i < omni_ext.len; i++) { out_path[olen] = omni_ext[i]; olen++; }
376→        out_path[olen] = 0;
377→
378→        // Get dep_name and dep_lib as slices
379→        usz dep_name_len = 0;
380→        while (dep_name[dep_name_len] != 0) dep_name_len++;
381→        usz dep_lib_len = 0;
382→        while (dep_lib[dep_lib_len] != 0) dep_lib_len++;
383→
384→        if (lisp::generate_ffi_module(dep_name[:dep_name_len], dep_lib[:dep_lib_len],
385→                                       funcs, func_count, out_path[:olen])) {
386→            io::printfn("  Generated %s (%d functions)", (ZString)&out_path[0], (int)func_count);
387→            total_bindings += func_count;
388→            total_libs++;
389→        } else {
390→            io::printfn("  Error: failed to write %s", (ZString)&out_path[0]);
391→        }
392→    }
393→
394→    io::printfn("\nGenerated %d bindings from %d libraries.", (int)total_bindings, (int)total_libs);
395→    return 0;
396→}
