423→/** Main entry point. */
424→fn int main(int argc, char** argv) {
425→    // Check for --help / -h flag
426→    for (int i = 1; i < argc; i++) {
427→        if (str_eq(argv[i], "--help") || str_eq(argv[i], "-h") || str_eq(argv[i], "-help")) {
428→            return print_help();
429→        }
430→    }
431→
432→    // Check for --version / -v flag
433→    for (int i = 1; i < argc; i++) {
434→        if (str_eq(argv[i], "--version") || str_eq(argv[i], "-v")) {
435→            io::printn("omni 0.1.0");
436→            return 0;
437→        }
438→    }
439→
440→    // Check for --init flag (scaffold new project)
441→    for (int i = 1; i < argc; i++) {
442→        if (str_eq(argv[i], "--init")) {
443→            return run_init(argc, argv, i);
444→        }
445→    }
446→
447→    // Check for --bind flag (generate FFI bindings)
448→    for (int i = 1; i < argc; i++) {
449→        if (str_eq(argv[i], "--bind")) {
450→            return run_bind(argc, argv, i);
451→        }
452→    }
453→
454→    // Check for --build flag (AOT compile to standalone binary)
455→    for (int i = 1; i < argc; i++) {
456→        if (str_eq(argv[i], "--build")) {
457→            return run_build(argc, argv, i);
458→        }
459→    }
460→
461→    // Check for compile flag
462→    bool run_compile = false;
463→    char* input_file = null;
464→    char* output_file = null;
465→    for (int i = 1; i < argc; i++) {
466→        if (str_eq(argv[i], "--compile") || str_eq(argv[i], "-compile")) {
467→            run_compile = true;
468→            if (i + 1 < argc) {
469→                input_file = argv[i + 1];
470→            }
471→            if (i + 2 < argc) {
472→                output_file = argv[i + 2];
473→            }
474→            break;
475→        }
476→    }
477→
478→    if (run_compile) {
479→        // Compile mode
480→        if (input_file == null || output_file == null) {
481→            io::printn("Usage: ./main --compile input.lisp output.c3");
482→            return 1;
483→        }
484→
485→        io::printfn("Compiling %s to %s...", (ZString)input_file, (ZString)output_file);
486→
487→        // Read input file
488→        char[] input_path;
489→        usz input_len = 0;
490→        char* p = input_file;
491→        while (*p != 0) { input_len++; p++; }
492→        input_path = input_file[:input_len];
493→
494→        if (try source = io::file::load_temp((String)input_path)) {
495→            // Initialize thread-local registry before interpreter
496→            thread_registry_init();
497→
498→            // Initialize interpreter for symbol table (heap-allocated due to size)
499→            lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
500→            interp.init();
501→
502→            // Compile to C3
503→            char[] c3_code = lisp::compile_to_c3(source, interp);
504→
505→            // Write output file
506→            char[] output_path;
507→            usz output_len = 0;
508→            p = output_file;
509→            while (*p != 0) { output_len++; p++; }
510→            output_path = output_file[:output_len];
511→
512→            if (try file = io::file::open((String)output_path, "w")) {
513→                defer (void)file.close();
514→                file.write(c3_code)!!;
515→                io::printfn("Compilation successful: %s", (ZString)output_file);
516→                mem::free(interp);
517→                thread_registry_shutdown();
518→                return 0;
519→            } else {
520→                io::printfn("Error: cannot write output file %s", (ZString)output_file);
521→                mem::free(interp);
522→                thread_registry_shutdown();
523→                return 1;
524→            }
525→        } else {
526→            io::printfn("Error: cannot read input file %s", (ZString)input_file);
527→            return 1;
528→        }
529→    }
530→
531→    // Check for --gen-e2e flag
532→    for (int i = 1; i < argc; i++) {
533→        if (str_eq(argv[i], "--gen-e2e")) {
534→            thread_registry_init();
535→            lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
536→            interp.init();
537→            lisp::register_primitives(interp);
538→            lisp::register_destructors();
539→            lisp::register_stdlib(interp);
540→            interp.flags.jit_enabled = true;
541→
542→            lisp::generate_e2e_tests(interp);
543→
544→            mem::free(interp);
545→            thread_registry_shutdown();
546→            return 0;
547→        }
548→    }
549→
550→    // Check for REPL flag
551→    bool run_repl = false;
552→    for (int i = 1; i < argc; i++) {
553→        if (str_eq(argv[i], "-repl") || str_eq(argv[i], "--repl")) {
554→            run_repl = true;
555→            break;
556→        }
557→    }
558→
559→    if (run_repl) {
560→        // Start REPL mode
561→        io::printn("Starting Lisp REPL...");
562→
563→        // Initialize thread-local registry first
564→        thread_registry_init();
565→
566→        // Initialize interpreter
567→        lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
568→        interp.init();
569→        lisp::register_primitives(interp);
570→        lisp::register_destructors();
571→        lisp::register_stdlib(interp);
572→        interp.flags.jit_enabled = true;
573→
574→        // Run REPL
575→        lisp::repl(interp);
576→
577→        // Clean up
578→        mem::free(interp);
579→        thread_registry_shutdown();
580→        return 0;
581→    }
582→
583→    // Check for script file argument (any arg that isn't a known flag)
584→    if (argc > 1) {
585→        // argv[1] is not --compile, -repl, or --repl — treat as script file
586→        char* script_file = argv[1];
587→        usz script_path_len = 0;
588→        char* sp = script_file;
589→        while (*sp != 0) { script_path_len++; sp++; }
590→        char[] script_path = script_file[:script_path_len];
591→
592→        // Read script file
593→        if (try source = io::file::load_temp((String)script_path)) {
594→            // Initialize thread-local registry
595→            thread_registry_init();
596→
597→            // Initialize interpreter
598→            lisp::Interp* interp = (lisp::Interp*)mem::malloc(lisp::Interp.sizeof);
599→            interp.init();
600→            lisp::register_primitives(interp);
601→            lisp::register_destructors();
602→            lisp::register_stdlib(interp);
603→            interp.flags.jit_enabled = true;
604→
605→            // Push script directory for relative import resolution
606→            lisp::push_source_dir(script_path, interp);
607→
608→            // Run the script (multiple expressions)
609→            usz len = source.len;
610→            if (len > 65535) len = 65535;
611→            char[] src = source[:len];
612→            lisp::EvalResult r = lisp::run_program(src, interp);
613→
614→            if (r.error.has_error) {
615→                // Print error
616→                usz msg_len = 0;
617→                while (msg_len < 256 && r.error.message[msg_len] != 0) {
618→                    msg_len++;
619→                }
620→                if (r.error.line > 0) {
621→                    io::printf("Error at line %d, column %d: ", (int)r.error.line, (int)r.error.column);
622→                } else {
623→                    io::print("Error: ");
624→                }
625→                for (usz i = 0; i < msg_len; i++) {
626→                    io::printf("%c", r.error.message[i]);
627→                }
628→                io::printn("");
629→                mem::free(interp);
630→                thread_registry_shutdown();
631→                return 1;
632→            }
633→
634→            // Print result if non-nil
635→            if (r.value != null && !lisp::is_nil(r.value)) {
636→                lisp::print_value(r.value, &interp.symbols);
637→                io::printn("");
638→            }
639→
640→            mem::free(interp);
641→            thread_registry_shutdown();
642→            return 0;
643→        } else {
644→            io::printfn("Error: cannot read script file '%s'", (ZString)script_file);
645→            return 1;
646→        }
647→    }
648→
649→    // Run tests mode
650→    io::printfn("Region Memory System v3 initialized");
651→
652→    // Run destructor registry tests (O(1) lookup implementation)
653→    run_destructor_registry_tests();
654→
655→    // Run ghost lookup tests (O(1) optimization verification)
656→    run_ghost_lookup_tests();
657→
658→    // Run stack engine tests (mmap stacks, context switch, coroutine lifecycle)
659→    run_stack_engine_tests();
660→
661→    // Run scope region tests (bump allocator, RC, freelist recycling)
662→    run_scope_region_tests();
663→
664→    // Initialize thread-local registry BEFORE Lisp tests (interpreter uses regions)
665→    thread_registry_init();
666→    io::printfn("Thread-local registry initialized, root id=%d", (uint)thread_registry().root_id);
667→
668→    // Run Lisp interpreter tests
669→    lisp::run_lisp_tests();
670→
671→    // Create a child region using convenience function
672→    RegionHandle child = create_region();
673→    io::printfn("Child region created: id=%d, gen=%d",
674→        (uint)child.region_id, (uint)child.generation);
675→
676→    // Clean up
677→    release_region(child);  // Release our reference
678→    thread_registry_shutdown();
679→
680→    io::printfn("System ready.");
681→    return 0;
682→}
