 45→// Initial capacities for dynamic tables
 46→const usz MACRO_INITIAL_CAPACITY = 32;
 47→const usz MODULE_INITIAL_CAPACITY = 16;
 48→const usz HANDLER_INITIAL_CAPACITY = 16;
 49→// Invalid symbol ID sentinel (returned on exhaustion; must not alias any valid index)
 50→const SymbolId INVALID_SYMBOL_ID = (SymbolId)0xFFFFFFFF;
 51→
 52→// Initial capacities for dynamic symbol table
 53→const usz SYMBOL_INITIAL_CAPACITY = 256;
 54→const usz SYMBOL_HASH_INITIAL_CAPACITY = 512;
