 71→/**
 72→ * SymbolTable — Table for interning symbol names (dynamic, growable).
 73→ */
 74→struct SymbolTable {
 75→    SymbolEntry* entries;
 76→    usz count;
 77→    usz capacity;           // entries array capacity
 78→    SymbolId* hash_index;   // Maps hash slot → symbol index (INVALID_SYMBOL_ID = empty)
 79→    usz hash_capacity;      // hash_index array capacity (power of 2)
 80→}
 81→
 82→fn void SymbolTable.init(SymbolTable* self) {
 83→    self.count = 0;
 84→    self.capacity = SYMBOL_INITIAL_CAPACITY;
 85→    self.hash_capacity = SYMBOL_HASH_INITIAL_CAPACITY;
 86→    self.entries = (SymbolEntry*)mem::malloc(SymbolEntry.sizeof * self.capacity);
 87→    self.hash_index = (SymbolId*)mem::malloc(SymbolId.sizeof * self.hash_capacity);
 88→    for (usz i = 0; i < self.hash_capacity; i++) {
 89→        self.hash_index[i] = INVALID_SYMBOL_ID;
 90→    }
 91→}
 92→
 93→fn void SymbolTable.destroy(SymbolTable* self) {
 94→    for (usz i = 0; i < self.count; i++) {
 95→        if (self.entries[i].name != null) {
 96→            mem::free(self.entries[i].name);
 97→        }
 98→    }
 99→    if (self.entries != null) {
100→        mem::free(self.entries);
101→        self.entries = null;
102→    }
103→    if (self.hash_index != null) {
104→        mem::free(self.hash_index);
105→        self.hash_index = null;
106→    }
107→}
108→
109→fn void SymbolTable.grow(SymbolTable* self) {
110→    // Double entries capacity
111→    usz new_cap = self.capacity * 2;
112→    SymbolEntry* new_entries = (SymbolEntry*)mem::malloc(SymbolEntry.sizeof * new_cap);
113→    for (usz i = 0; i < self.count; i++) {
114→        new_entries[i] = self.entries[i];
115→    }
116→    mem::free(self.entries);
117→    self.entries = new_entries;
118→    self.capacity = new_cap;
119→
120→    // Double hash capacity and rebuild
121→    usz new_hash_cap = self.hash_capacity * 2;
122→    mem::free(self.hash_index);
123→    self.hash_index = (SymbolId*)mem::malloc(SymbolId.sizeof * new_hash_cap);
124→    self.hash_capacity = new_hash_cap;
125→    for (usz i = 0; i < new_hash_cap; i++) {
126→        self.hash_index[i] = INVALID_SYMBOL_ID;
127→    }
128→    // Re-insert all entries into new hash table
129→    usz mask = new_hash_cap - 1;
130→    for (usz i = 0; i < self.count; i++) {
131→        usz h = hash_symbol(self.entries[i].name[:self.entries[i].len]);
132→        for (usz probe = 0; probe < new_hash_cap; probe++) {
133→            usz slot = (h + probe) & mask;
134→            if (self.hash_index[slot] == INVALID_SYMBOL_ID) {
135→                self.hash_index[slot] = (SymbolId)i;
136→                break;
137→            }
138→        }
139→    }
140→}
141→
142→/**
143→ * hash_symbol — FNV-1a hash for symbol names.
144→ */
145→fn usz hash_symbol(char[] name) {
146→    usz h = 2166136261;  // FNV offset basis (32-bit)
147→    for (usz i = 0; i < name.len; i++) {
148→        h ^= (usz)name[i];
149→        h *= 16777619;   // FNV prime (32-bit)
150→    }
151→    return h;
152→}
153→
154→fn SymbolId SymbolTable.intern(SymbolTable* self, char[] name) {
155→    usz h = hash_symbol(name);
156→    usz mask = self.hash_capacity - 1;
157→
158→    // Hash table lookup with linear probing
159→    for (usz probe = 0; probe < self.hash_capacity; probe++) {
160→        usz slot = (h + probe) & mask;
161→        SymbolId sid = self.hash_index[slot];
162→        if (sid == INVALID_SYMBOL_ID) {
163→            // Empty slot: symbol not in hash table, stop probing
164→            break;
165→        }
166→        // Check if this slot's entry matches
167→        usz idx = (usz)sid;
168→        if (self.entries[idx].len == name.len) {
169→            bool match = true;
170→            for (usz j = 0; j < name.len; j++) {
171→                if (self.entries[idx].name[j] != name[j]) {
172→                    match = false;
173→                    break;
174→                }
175→            }
176→            if (match) {
177→                return sid;
178→            }
179→        }
180→    }
181→
182→    // Grow at 70% load factor
183→    if (self.count * 10 >= self.capacity * 7) {
184→        self.grow();
185→        mask = self.hash_capacity - 1;
186→        h = hash_symbol(name);  // recompute with new mask
187→    }
188→
189→    // Insert new symbol
190→    SymbolId id = (SymbolId)self.count;
191→    usz len = name.len;
192→    // Heap-allocate symbol name
193→    char* heap_name = (char*)mem::malloc(len + 1);
194→    for (usz i = 0; i < len; i++) {
195→        heap_name[i] = name[i];
196→    }
197→    heap_name[len] = 0;
198→    self.entries[self.count].name = heap_name;
199→    self.entries[self.count].len = len;
200→    self.count++;

