1632→    usz idx = (usz)(uint)id;
1633→    Region* region = &self.region_storage[idx];
1634→    RegionId parent_id = region.parent;
1635→    bool has_parent = (parent_id != NO_PARENT);
1636→
1637→    // ============================================================
1638→    //  PHASE 1: PROMOTE ESCAPED OBJECTS, DESTROY LOCAL OBJECTS
1639→    // ============================================================
