1641→    // Local objects (never escaped) are destroyed with the region.
1642→    if (has_parent) {
1643→        usz parent_idx = (usz)(uint)parent_id;
1644→        Region* parent_region = &self.region_storage[parent_idx];
1645→
1646→        uint[] live_slots = region.slot_table.live_slot_tracker.get_live_keys();
1647→
1648→        for (usz i = 0; i < live_slots.len; i++) {
1649→            SlotId sid = (SlotId)live_slots[i];
1650→            ObjectRecord* record = region.slot_table.get_record(sid);
