  1→/**
  2→ * =============================================================================
  3→ * GHOST INDEX — O(1) Ghost Table Lookup
  4→ * =============================================================================
  5→ *
  6→ * Provides O(1) lookup of ghost tables by combining the source region ID and
  7→ * generation into a single 64-bit key. Uses open-addressing hash map with
  8→ * linear probing.
  9→ *
 10→ * Key composition: (region_id << 32) | generation
 11→ * This ensures unique keys for each (region_id, generation) pair.
 12→ */
 13→module main;
 14→
 15→import std::collections::list;
 16→
 17→// =============================================================================
 18→// GHOST INDEX STRUCTURES
 19→// =============================================================================
 20→
 21→/** Sentinel value for empty slots in the ghost index. */
 22→const ulong GHOST_INDEX_EMPTY = ulong.max;
 23→
 24→/** Sentinel value for tombstoned (deleted) slots in the ghost index. */
 25→const ulong GHOST_INDEX_TOMBSTONE = ulong.max - (ulong)1;
 26→
 27→/**
 28→ * GhostIndexEntry — A single entry in the ghost index hash map.
 29→ *
 30→ * Fields:
 31→ *   key       — Combined (region_id << 32) | generation, or GHOST_INDEX_EMPTY
 32→ *   host_id   — Region ID that holds the ghost table
 33→ *   ghost_idx — Index into host region's inherited_ghost_tables list
 34→ */
 35→struct GhostIndexEntry {
 36→    ulong    key;       // (source_region_id << 32) | source_generation
 37→    RegionId host_id;   // Which region holds the ghost table
 38→    usz      ghost_idx; // Index into host's inherited_ghost_tables
 39→}
 40→
 41→/**
 42→ * GhostIndex — O(1) hash map for ghost table lookup.
 43→ *
 44→ * Uses open-addressing with linear probing. Automatically resizes when
 45→ * load factor exceeds 0.75.
 46→ *
 47→ * Fields:
 48→ *   entries  — Fixed-size array of entries (power of 2)
 49→ *   count    — Number of occupied entries
 50→ *   capacity — Total slots (always power of 2)
 51→ */
 52→struct GhostIndex {
 53→    List{GhostIndexEntry} entries;
 54→    usz count;
 55→    usz capacity;
 56→}
 57→
 58→/**
 59→ * Lookup result for ghost index queries.
 60→ */
 61→struct GhostLookupResult {
 62→    bool     found;
 63→    RegionId host_id;
 64→    usz      ghost_idx;
 65→}
 66→
 67→// =============================================================================
 68→// GHOST INDEX FUNCTIONS
 69→// =============================================================================
 70→
 71→/**
 72→ * Compose a lookup key from region ID and generation.
 73→ */
 74→fn ulong ghost_index_make_key(RegionId region_id, Generation gen) @inline {
 75→    return ((ulong)(uint)region_id << 32) | (ulong)(uint)gen;
 76→}
 77→
 78→/**
 79→ * Hash function for ghost index keys.
 80→ * Uses splitmix64-style mixing for good distribution.
 81→ */
 82→fn usz ghost_index_hash(ulong key) @inline {
 83→    ulong h = key;
 84→    h ^= h >> 33;
 85→    h *= 0xff51afd7ed558ccd;
 86→    h ^= h >> 33;
 87→    h *= 0xc4ceb9fe1a85ec53;
 88→    h ^= h >> 33;
 89→    return (usz)h;
 90→}
 91→
 92→/**
 93→ * Initialize the ghost index with a given capacity.
 94→ *
 95→ * @param initial_capacity Minimum number of slots (will be rounded up to power of 2)
 96→ */
 97→fn void GhostIndex.init(GhostIndex* self, usz initial_capacity) {
 98→    // Round up to power of 2
 99→    usz cap = 16; // minimum
100→    while (cap < initial_capacity) cap *= 2;
101→
102→    self.capacity = cap;
103→    self.count = 0;
104→
105→    // Initialize all entries as empty
106→    for (usz i = 0; i < cap; i++) {
107→        GhostIndexEntry empty = { .key = GHOST_INDEX_EMPTY, .host_id = 0, .ghost_idx = 0 };
108→        self.entries.push(empty);
109→    }
110→}
111→
112→/**
113→ * Resize the ghost index when load factor is too high.
114→ * Called automatically by insert when load > 75%.
115→ */
116→fn void GhostIndex.resize(GhostIndex* self) {
117→    usz new_capacity = self.capacity * 2;
118→    List{GhostIndexEntry} old_entries = self.entries;
119→
120→    // Create new empty entries
121→    self.entries = {};
122→    for (usz i = 0; i < new_capacity; i++) {
123→        GhostIndexEntry empty = { .key = GHOST_INDEX_EMPTY, .host_id = 0, .ghost_idx = 0 };
124→        self.entries.push(empty);
125→    }
126→    self.capacity = new_capacity;
127→    self.count = 0;
128→
129→    // Re-insert all existing entries (skip empty and tombstone slots)
130→    foreach (&entry : old_entries) {
131→        if (entry.key != GHOST_INDEX_EMPTY && entry.key != GHOST_INDEX_TOMBSTONE) {
132→            self.insert_entry(entry.key, entry.host_id, entry.ghost_idx);
133→        }
134→    }
135→
136→    old_entries.free();
137→}
138→
139→/**
140→ * Insert an entry into the ghost index by raw key.
141→ * Checks for duplicates and updates in-place if the key already exists.
142→ * Also reuses tombstone slots during probing.
143→ *
144→ * @param key       The 64-bit composite key
145→ * @param host_id   Region holding the ghost table
146→ * @param ghost_idx Index into host's ghost table list
147→ */
148→fn void GhostIndex.insert_entry(GhostIndex* self, ulong key, RegionId host_id, usz ghost_idx) {
149→    // Check load factor and resize if needed (> 75%)
150→    if (self.count * 4 >= self.capacity * 3) {
151→        self.resize();
152→    }
153→
154→    usz mask = self.capacity - 1;
155→    usz idx = ghost_index_hash(key) & mask;
156→
157→    // Linear probing: check for duplicates, reuse tombstones
158→    usz first_tombstone = usz.max;  // Track first tombstone for reuse
159→    while (self.entries[idx].key != GHOST_INDEX_EMPTY) {
160→        if (self.entries[idx].key == key) {
161→            // Duplicate key found — update in-place
162→            self.entries[idx].host_id = host_id;
163→            self.entries[idx].ghost_idx = ghost_idx;
164→            return;
165→        }
166→        if (self.entries[idx].key == GHOST_INDEX_TOMBSTONE && first_tombstone == usz.max) {
167→            first_tombstone = idx;
168→        }
169→        idx = (idx + 1) & mask;
170→    }
171→
172→    // Use tombstone slot if available, otherwise use the empty slot
173→    usz target = (first_tombstone != usz.max) ? first_tombstone : idx;
174→    self.entries[target].key = key;
175→    self.entries[target].host_id = host_id;
176→    self.entries[target].ghost_idx = ghost_idx;
177→    self.count++;
178→}
179→
180→/**
181→ * Insert a ghost table mapping into the index.
182→ *
183→ * @param source_id  The dead region's ID
184→ * @param gen        The dead region's generation at time of death
185→ * @param host_id    The region holding the ghost table
186→ * @param ghost_idx  Index into host's inherited_ghost_tables list
187→ */
188→fn void GhostIndex.insert(GhostIndex* self, RegionId source_id, Generation gen,
189→                          RegionId host_id, usz ghost_idx) {
190→    ulong key = ghost_index_make_key(source_id, gen);
191→    self.insert_entry(key, host_id, ghost_idx);
192→}
193→
194→/**
195→ * Look up a ghost table by source region ID and generation.
196→ *
197→ * @param source_id  The dead region's ID
198→ * @param gen        The dead region's generation
199→ * @return GhostLookupResult with found=true if entry exists
200→ */
201→fn GhostLookupResult GhostIndex.lookup(GhostIndex* self, RegionId source_id, Generation gen) {
202→    if (self.capacity == 0) {
203→        return { .found = false, .host_id = 0, .ghost_idx = 0 };
204→    }
205→
206→    ulong key = ghost_index_make_key(source_id, gen);
207→    usz mask = self.capacity - 1;
208→    usz idx = ghost_index_hash(key) & mask;
209→    usz start = idx;
210→
211→    // Linear probing (skip tombstones, stop at empty)
212→    do {
213→        if (self.entries[idx].key == key) {
214→            return {
215→                .found = true,
216→                .host_id = self.entries[idx].host_id,
217→                .ghost_idx = self.entries[idx].ghost_idx
218→            };
219→        }
220→        if (self.entries[idx].key == GHOST_INDEX_EMPTY) {
221→            // Empty slot means key not in table
222→            return { .found = false, .host_id = 0, .ghost_idx = 0 };
223→        }
224→        // Tombstone slots are skipped — continue probing
225→        idx = (idx + 1) & mask;
226→    } while (idx != start);
227→
228→    return { .found = false, .host_id = 0, .ghost_idx = 0 };
229→}
230→
231→/**
232→ * Update an existing entry in the ghost index.
233→ *
234→ * Finds an entry by its source region ID and generation, then updates
235→ * the host_id and ghost_idx to new values. Used when re-promoting
236→ * inherited ghost tables to a new parent.
237→ *
238→ * @param source_id      The dead region's ID (key part 1)
239→ * @param gen            The dead region's generation (key part 2)
240→ * @param new_host_id    The new region holding the ghost table
241→ * @param new_ghost_idx  The new index into host's inherited_ghost_tables
242→ * @return true if entry was found and updated, false if not found
243→ */
244→fn bool GhostIndex.update(GhostIndex* self, RegionId source_id, Generation gen,
245→                          RegionId new_host_id, usz new_ghost_idx) {
246→    if (self.capacity == 0) {
247→        return false;
248→    }
249→
250→    ulong key = ghost_index_make_key(source_id, gen);
251→    usz mask = self.capacity - 1;
252→    usz idx = ghost_index_hash(key) & mask;
253→    usz start = idx;
254→
255→    // Linear probing to find the entry (skip tombstones, stop at empty)
256→    do {
257→        if (self.entries[idx].key == key) {
258→            // Found it — update the values
259→            self.entries[idx].host_id = new_host_id;
260→            self.entries[idx].ghost_idx = new_ghost_idx;
261→            return true;
262→        }
263→        if (self.entries[idx].key == GHOST_INDEX_EMPTY) {
264→            // Empty slot means key not in table
265→            return false;
266→        }
267→        // Tombstone slots are skipped — continue probing
268→        idx = (idx + 1) & mask;
269→    } while (idx != start);
270→
271→    return false;
272→}
273→
274→/**
275→ * Remove an entry from the ghost index by source region ID and generation.
276→ *
277→ * Uses tombstone-based deletion: the entry's key is replaced with
278→ * GHOST_INDEX_TOMBSTONE so that linear probing continues past it.
279→ *
280→ * @param source_id  The dead region's ID
281→ * @param gen        The dead region's generation
282→ * @return true if entry was found and removed, false if not found
283→ */
284→fn bool GhostIndex.remove(GhostIndex* self, RegionId source_id, Generation gen) {
285→    if (self.capacity == 0) {
286→        return false;
287→    }
288→
289→    ulong key = ghost_index_make_key(source_id, gen);
290→    usz mask = self.capacity - 1;
291→    usz idx = ghost_index_hash(key) & mask;
292→    usz start = idx;
293→
294→    // Linear probing to find the entry (skip tombstones, stop at empty)
295→    do {
296→        if (self.entries[idx].key == key) {
297→            // Found it — mark as tombstone
298→            self.entries[idx].key = GHOST_INDEX_TOMBSTONE;
299→            self.count--;
300→            return true;
301→        }
302→        if (self.entries[idx].key == GHOST_INDEX_EMPTY) {
303→            // Empty slot means key not in table
304→            return false;
305→        }
306→        // Tombstone slots are skipped — continue probing
307→        idx = (idx + 1) & mask;
308→    } while (idx != start);
309→
310→    return false;
311→}
312→
313→/**
314→ * Free all resources held by the ghost index.
315→ */
316→fn void GhostIndex.release(GhostIndex* self) {
317→    self.entries.free();
318→    self.count = 0;
319→    self.capacity = 0;
320→}
