    for (usz i = 0; i < sub_src.len; i++) { path_buf[plen] = sub_src[i]; plen++; }
    path_buf[plen] = 0;
    mkdir(&path_buf[0], 0o755);

    // name/lib/
    plen = name_len;
    path_buf[plen] = '/'; plen++;
