    // name/build/
    plen = name_len;
    path_buf[plen] = '/'; plen++;
    char[] sub_build = "build";
    for (usz i = 0; i < sub_build.len; i++) { path_buf[plen] = sub_build[i]; plen++; }
    path_buf[plen] = 0;
